/**
 * createRateLimiter — a TRUE sliding window rate limiting middleware for Express.
 *
 * Unlike a fixed-window limiter (which resets a counter at fixed interval
 * boundaries and can allow up to 2x maxRequests across a boundary), this
 * implementation stores the timestamp of every request per client and, on each
 * incoming request, discards timestamps older than `windowMs` before counting.
 * The window therefore "slides" continuously with the current time.
 *
 * @param {Object} [options]
 * @param {number} [options.windowMs=60000]   Window size in milliseconds.
 * @param {number} [options.maxRequests=100]  Max requests allowed per window.
 * @returns {Function} Express middleware, augmented with a `close()` method
 *                     that clears the internal cleanup timer.
 */
function createRateLimiter(options = {}) {
  const windowMs = options.windowMs ?? 60000;
  const maxRequests = options.maxRequests ?? 100;

  // Map<clientKey, number[]> — array of request timestamps (ms epoch).
  // Kept sorted ascending because we only ever push "now" (monotonically
  // increasing in practice) and trim from the front.
  const hits = new Map();

  /**
   * Drop timestamps that fall outside the sliding window (now - windowMs, now].
   * Mutates the array in place and returns it.
   */
  function prune(timestamps, now) {
    const cutoff = now - windowMs;
    let i = 0;
    while (i < timestamps.length && timestamps[i] <= cutoff) {
      i++;
    }
    if (i > 0) {
      timestamps.splice(0, i);
    }
    return timestamps;
  }

  const middleware = function rateLimiter(req, res, next) {
    // NOTE ON req.ip BEHIND PROXIES:
    // `req.ip` is derived from the socket address UNLESS Express "trust proxy"
    // is enabled. Behind a reverse proxy / load balancer (Nginx, ELB, etc.)
    // every request appears to come from the proxy's IP, so all clients would
    // share one bucket. Enable it on your app so Express reads the real client
    // IP from the X-Forwarded-For header:
    //     app.set('trust proxy', 1);   // 1 = trust the first hop (your proxy)
    // Only enable this when you actually run behind a trusted proxy — otherwise
    // clients can spoof X-Forwarded-For to evade the limiter.
    const key = req.ip || req.socket?.remoteAddress || 'unknown';

    const now = Date.now();

    let timestamps = hits.get(key);
    if (!timestamps) {
      timestamps = [];
      hits.set(key, timestamps);
    }

    // Slide the window: remove everything older than windowMs.
    prune(timestamps, now);

    const used = timestamps.length;

    if (used >= maxRequests) {
      // Over the limit — reject. The oldest in-window request determines when
      // a slot frees up: it expires at oldest + windowMs.
      const oldest = timestamps[0];
      const resetMs = oldest + windowMs;
      const retryAfterSec = Math.max(1, Math.ceil((resetMs - now) / 1000));

      res.setHeader('X-RateLimit-Limit', maxRequests);
      res.setHeader('X-RateLimit-Remaining', 0);
      res.setHeader('X-RateLimit-Reset', Math.ceil(resetMs / 1000));
      res.setHeader('Retry-After', retryAfterSec);

      res.status(429).json({
        error: 'Rate limit exceeded',
        retryAfter: retryAfterSec,
      });
      return; // Do NOT call next().
    }

    // Under the limit — record this request and allow it.
    timestamps.push(now);

    const remaining = maxRequests - timestamps.length;
    // When does the window free up next? When the current oldest expires.
    const resetMs = timestamps[0] + windowMs;

    res.setHeader('X-RateLimit-Limit', maxRequests);
    res.setHeader('X-RateLimit-Remaining', Math.max(0, remaining));
    res.setHeader('X-RateLimit-Reset', Math.ceil(resetMs / 1000));

    next();
  };

  // ---- Memory management -------------------------------------------------
  // Periodically sweep the map and delete buckets whose timestamps are all
  // outside the window, so idle/one-off IPs don't accumulate forever.
  const cleanupInterval = setInterval(() => {
    const now = Date.now();
    for (const [key, timestamps] of hits) {
      prune(timestamps, now);
      if (timestamps.length === 0) {
        hits.delete(key);
      }
    }
  }, 60000);

  // Don't let the cleanup timer keep the Node process alive on its own.
  if (typeof cleanupInterval.unref === 'function') {
    cleanupInterval.unref();
