/**
 * Sliding Window Rate Limiter Middleware for Express.js
 *
 * TRUE sliding window: each client's request timestamps are stored
 * individually. On every request the window is computed relative to *now*,
 * so there is no fixed-interval reset artefact that would allow a burst at
 * the seam between two fixed windows.
 *
 * ── Proxy note ──────────────────────────────────────────────────────────────
 * `req.ip` is set by Express from the raw socket address by default.  Behind
 * a reverse proxy (Nginx, Cloudflare, …) every request arrives from the
 * proxy's IP, so ALL clients share a single rate-limit bucket — defeating the
 * whole point.  Fix this before mounting the middleware:
 *
 *   app.set('trust proxy', 1);          // trust the first hop (same-host Nginx)
 *   app.set('trust proxy', 'loopback'); // trust 127.x.x.x / ::1 hops only
 *
 * Express will then read the real client IP from X-Forwarded-For.  Never
 * trust more hops than you actually control — extra hops can be spoofed.
 * ────────────────────────────────────────────────────────────────────────────
 */

/**
 * @typedef {Object} RateLimiterOptions
 * @property {number} [windowMs=60000]   - Sliding window size in ms (default 1 min)
 * @property {number} [maxRequests=100]  - Max requests allowed per window
 */

/**
 * @typedef {Object} RateLimiter
 * @property {Function} middleware - Express-compatible `(req, res, next) => void`
 * @property {Function} close      - Cancels the background cleanup interval
 */

/**
 * Factory that creates a sliding-window rate-limiter.
 *
 * @param {RateLimiterOptions} [options]
 * @returns {RateLimiter}
 */
function createRateLimiter(options = {}) {
  const windowMs    = options.windowMs    ?? 60_000; // default: 1 minute
  const maxRequests = options.maxRequests ?? 100;    // default: 100 req / window

  if (typeof windowMs !== 'number' || windowMs <= 0) {
    throw new TypeError('windowMs must be a positive number');
  }
  if (typeof maxRequests !== 'number' || maxRequests <= 0) {
    throw new TypeError('maxRequests must be a positive number');
  }

  /**
   * Per-IP timestamp store.
   *
   *   Map<string ip, number[] timestamps>
   *
   * Each array holds the epoch-ms timestamps of every request still inside
   * the current window for that IP.  Arrays are kept in ascending order so
   * stale entries cluster at index 0, enabling O(log n) eviction via binary
   * search followed by a single splice from the front.
   */
  const store = new Map();

  // ── Core algorithm helpers ────────────────────────────────────────────────

  /**
   * Slide the window forward: drop all timestamps that now fall outside it.
   *
   * Because the array is sorted ascending, every stale entry is at the front.
   * We binary-search for the first timestamp still inside the window and
   * splice everything before it in one call — O(log n + evicted).
   *
   * @param {number[]} timestamps - Mutated in place (sorted ascending)
   * @param {number}   now        - Current epoch ms
   */
  function evictStale(timestamps, now) {
    const cutoff = now - windowMs; // anything <= cutoff is outside the window

    // Binary search for the leftmost index whose value > cutoff
    let lo = 0;
    let hi = timestamps.length;
    while (lo < hi) {
      const mid = (lo + hi) >>> 1;
      if (timestamps[mid] <= cutoff) {
        lo = mid + 1;
      } else {
        hi = mid;
      }
    }

    if (lo > 0) timestamps.splice(0, lo);
  }

  // ── Background memory management ─────────────────────────────────────────
  //
  // Runs every 60 s.  Walks the entire store, evicts stale timestamps from
  // each IP's array, then deletes the Map entry if the array is now empty.
  // This prevents unbounded growth when large numbers of unique IPs visit
  // once and are never seen again.

  const cleanupInterval = setInterval(() => {
    const now = Date.now();
    for (const [ip, timestamps] of store) {
      evictStale(timestamps, now);
      if (timestamps.length === 0) {
        store.delete(ip);
      }
    }
  }, 60_000);

  // `unref()` marks the timer as non-blocking: Node.js can exit even if the
  // interval is still pending.  Without this, a test suite (or graceful
  // shutdown) would hang waiting for the timer to fire.
  if (cleanupInterval.unref) cleanupInterval.unref();

  // ── Middleware ────────────────────────────────────────────────────────────

  /**
   * Express middleware implementing the sliding-window check.
   *
   * Algorithm per request
   * ─────────────────────
   * 1. Fetch (or initialise) the timestamp array for this client IP.
   * 2. Evict all timestamps older than windowMs from *now*.
   * 3. Count remaining entries.
   *    a. count >= maxRequests → reject with 429; compute retryAfter from
   *       oldest in-window timestamp so the client knows exactly how long to
   *       wait for one slot to open.
   *    b. count < maxRequests  → append now, set informational headers, call
   *       next().
   *
   * @param {import('express').Request}      req
   * @param {import('express').Response}     res
   * @param {import('express').NextFunction} next
   */
  function middleware(req, res, next) {
    // req.ip may be undefined in unit tests; fall back to raw socket address.
    const ip  = req.ip || req.socket?.remoteAddress || 'unknown';
    const now = Date.now();

    if (!store.has(ip)) store.set(ip, []);
    const timestamps = store.get(ip);

    // Step 1 – slide the window
    evictStale(timestamps, now);

    const currentCount = timestamps.length;

    // ── Step 2a: REJECTED ──────────────────────────────────────────────────
    if (currentCount >= maxRequests) {
      // timestamps[0] is the oldest request still inside the window.
      // It will exit the window at (timestamps[0] + windowMs), freeing one
      // slot — that is the earliest the client can retry.
      const oldestInWindow = timestamps[0];
      const retryAfterMs   = oldestInWindow + windowMs - now;
      const retryAfterSec  = Math.ceil(retryAfterMs / 1000);

      res.set('Retry-After', String(retryAfterSec));
      return res.status(429).json({
        error:      'Rate limit exceeded',
        retryAfter: retryAfterSec,
      });
    }

    // ── Step 2b: ALLOWED ───────────────────────────────────────────────────
    // Record this request (appending keeps the array sorted ascending because
    // `now` is always >= all previous timestamps).
    timestamps.push(now);

    // X-RateLimit-Reset: the epoch second at which the *oldest* recorded
    // request exits the window — i.e., when the next slot is guaranteed to
    // become available.  (timestamps[0] is the one we just pushed if this is
    // the first request in the window, which is fine — it gives a full window
    // from now.)
    const resetEpochSec = Math.ceil((timestamps[0] + windowMs) / 1000);

    res.set({
      'X-RateLimit-Limit':     String(maxRequests),
      'X-RateLimit-Remaining': String(maxRequests - timestamps.length),
      'X-RateLimit-Reset':     String(resetEpochSec),
    });

    next();
  }

  // ── Public API ────────────────────────────────────────────────────────────

  /**
   * Stop the background cleanup timer.
   *
   * Call this when your HTTP server closes so Node.js can exit cleanly:
   *
   *   server.on('close', () => limiter.close());
   */
  function close() {
    clearInterval(cleanupInterval);
  }

  return { middleware, close };
}

module.exports = { createRateLimiter };
