const authLimiter = createRateLimiter({
  windowMs:    15 * 60_000, // 15-minute window
  maxRequests: 10,          // only 10 login attempts per 15 min
});

// Mount globally on /api
app.use('/api', apiLimiter.middleware);

// Mount narrowly on a specific route (limiter runs before the handler)
