  res.json({ token: 'example' });
});

app.get('/api/data', (req, res) => {
  res.json({ ok: true });
});

const server = app.listen(3000, () =>
  console.log('Listening on http://localhost:3000'),
);

// Clean up intervals on shutdown so the process exits immediately
server.on('close', () => {
  apiLimiter.close();
  authLimiter.close();
});
